const SPECIES = [
 { name:'이끼', type:'BRYOPHYTE', color:'#1a6b3c', gr:1.5, disp:0.5 },
 { name:'토양 미생물', type:'MICROBE', color:'#2e8b57', gr:1.5, disp:0.4 },
 { name:'분해자', type:'INVERTEBRATE',color:'#e67e22', gr:1.3, disp:0.6 },
 { name:'교목', type:'PLANT', color:'#2980b9', gr:0.6, disp:0.2 },
 { name:'관목', type:'PLANT', color:'#27ae60', gr:1.0, disp:0.4 },
 { name:'초본', type:'PLANT', color:'#16a085', gr:1.3, disp:0.5 },
 { name:'조류', type:'VERTEBRATE', color:'#c0392b', gr:0.4, disp:0.9 },
 { name:'설치류', type:'VERTEBRATE', color:'#8e44ad', gr:0.9, disp:0.7 },
 { name:'곤충', type:'INVERTEBRATE',color:'#d35400', gr:0.8, disp:0.8 },
];
const SHORT_YEARS = [1,2,3];
const LONG_YEARS = [1,5,10,15];
const SNAPSHOT_YEARS = [1,2,3,5,10,15];
const GS = 100;
let currentPeriodMode = 'long';
function getSelectedYears(){ return currentPeriodMode==='short'?SHORT_YEARS:LONG_YEARS; }
function formatYearLabel(y){ return `${y}년 후`; }
function formatYearsSubtitle(years){ return years.map(formatYearLabel).join('→'); }

