function getSpeciesName(key){
  const raw=String(key||'');
  const norm=raw.trim();
  const map={'rodent':'설치류','Rodent':'설치류','insect':'곤충','Insect':'곤충',
    'moss_a':'이끼','Moss_A':'이끼','이끼':'이끼',
    'microbial_b':'토양 미생물','Microbial_B':'토양 미생물','토양 미생물':'토양 미생물',
    'detritivore_c':'분해자','Detritivore_C':'분해자','분해자':'분해자',
    'tree_d':'교목','Tree_D':'교목','교목':'교목',
    'shrub_e':'관목','Shrub_E':'관목','관목':'관목',
    'herb_f':'초본','Herb_F':'초본','초본':'초본',
    'bird_g':'조류','Bird_G':'조류','조류':'조류'
  };
  return map[norm]||norm;
}

