function getRichnessState(v) {
  if (v < 3) return { label: "낮음", cls: "low" };
  if (v < 6) return { label: "보통", cls: "mid" };
  return { label: "높음", cls: "high" };
}

function getDensityState(v) {
  if (v < 5) return { label: "초기", cls: "low" };
  if (v < 10) return { label: "진행", cls: "mid" };
  return { label: "안정", cls: "high" };
}

function getAreaState(v) {
  if (v < 10) return { label: "초기", cls: "low" };
  if (v < 30) return { label: "진행", cls: "mid" };
  return { label: "확산", cls: "high" };
}
function hashStr(s){ let h=0; for(const c of s) h=(h*31+c.charCodeAt(0))&0xffffffff; return Math.abs(h)%1000; }
function snoise(x,y){ return Math.sin(x*1.37+y*2.71)*0.5+Math.sin(x*2.33-y*1.11)*0.3+Math.sin((x+y)*0.97)*0.2; }

function makeIrregularMask(seed){
 const mask=new Float32Array(GS*GS);
 const cx=GS*(0.38+(seed%7)*0.03), cy=GS*(0.42+(seed%5)*0.03);
 const rx=GS*(0.20+(seed%3)*0.03), ry=GS*(0.26+(seed%4)*0.02);
 for(let r=0;r<GS;r++) for(let c=0;c<GS;c++){
 const dx=(c-cx)/rx, dy=(r-cy)/ry;
 const n=snoise(c/GS*4+seed*0.1,r/GS*4+seed*0.3)*0.3;
 if(Math.sqrt(dx*dx+dy*dy)+n<1.0) mask[r*GS+c]=1;
 }
 return mask;
}

function makeEnvScore(mask){
 const env=new Float32Array(GS*GS); let mn=Infinity,mx=-Infinity;
 for(let i=0;i<GS*GS;i++){
 if(!mask[i]) continue;
 const r=Math.floor(i/GS)/GS, c=(i%GS)/GS;
 env[i]=0.4+0.5*(snoise(r*3,c*3)*0.5+0.5);
 mn=Math.min(mn,env[i]); mx=Math.max(mx,env[i]);
 }
 for(let i=0;i<GS*GS;i++) if(mask[i]) env[i]=(env[i]-mn)/(mx-mn+1e-9);
 return env;
}

function simulateYear(prev,mask,env,year){
 const K=25, n=SPECIES.length;
 const next=prev.map(a=>new Float32Array(a));
 for(let sp=0;sp<n;sp++){
 const {gr,disp}=SPECIES[sp];
 for(let i=0;i<GS*GS;i++){
 if(!mask[i]){next[sp][i]=0;continue;}
 const cap=K*env[i]*(1+0.015*year);
 const h=prev[sp][i];
 const r=gr*(1-h/(cap+1e-6))-0.09;
 next[sp][i]=Math.max(0,h+h*r+(Math.random()-0.5)*0.4);
 }
 if(disp>0.3) for(let row=1;row<GS-1;row++) for(let col=1;col<GS-1;col++){
 if(!mask[row*GS+col]) continue;
 const center=next[sp][row*GS+col];
 const avg=(next[sp][(row-1)*GS+col]+next[sp][(row+1)*GS+col]+next[sp][row*GS+col-1]+next[sp][row*GS+col+1])/4;
 next[sp][row*GS+col]=center+disp*0.05*(avg-center);
 }
 }
 return next;
}

function runModel(seed){
 const mask=makeIrregularMask(seed), env=makeEnvScore(mask), n=SPECIES.length;
 let state=SPECIES.map((sp,si)=>{
 const h=new Float32Array(GS*GS);
 const mc=[]; for(let i=0;i<GS*GS;i++) if(mask[i]) mc.push(i);
 const patches=si===0?3:1, ps=si===0?12:5;
 for(let p=0;p<patches;p++){
 const idx=mc[Math.floor(Math.random()*mc.length)]||0;
 const cr=Math.floor(idx/GS), cc=idx%GS;
 for(let dr=-ps;dr<ps;dr++) for(let dc=-ps;dc<ps;dc++){
 const nr=cr+dr, nc=cc+dc;
 if(nr>=0&&nr<GS&&nc>=0&&nc<GS&&mask[nr*GS+nc]) if(Math.random()>0.4) h[nr*GS+nc]=Math.random()*5;
 }
 }
 return h;
 });
 const snaps={};
 for(let y=1;y<=15;y++){
 state=simulateYear(state,mask,env,y);
 if(SNAPSHOT_YEARS.includes(y)) snaps[y]=state.map(a=>new Float32Array(a));
 }
 const richMeans={}, densMeans={};
 SNAPSHOT_YEARS.forEach(y=>{
 const snap=snaps[y]; let tr=0,td=0,cells=0;
 for(let i=0;i<GS*GS;i++){
 if(!mask[i]) continue; cells++;
 let rich=0,dens=0;
 for(let sp=0;sp<n;sp++){if(snap[sp][i]>1)rich++;dens+=snap[sp][i];}
 tr+=rich; td+=dens/n;
 }
 richMeans[y]=tr/cells; densMeans[y]=td/cells;
 });
 const activeCells=mask.reduce((a,v)=>a+v,0);
 let envSum=0,envCells=0; for(let i=0;i<GS*GS;i++) if(mask[i]){envSum+=env[i];envCells++;}
 return {mask,env,snaps,richMeans,densMeans,activeCells,envMean:envSum/envCells};
}

// ═══════════════════════════════════
// RENDERING
// ═══════════════════════════════════
function richnessColor(v,max=9){
 const t=Math.min(v/max,1);
 if(t<0.01) return [220,230,235];
 return [Math.round(30+210*t), Math.round(80-40*t), Math.round(160*(1-t)+30)];
}
function densityColor(v,max=25){
 const t=Math.min(v/max,1);
 if(t<0.01) return [240,245,235];
 return [Math.round(240-190*t), Math.round(245-120*t), Math.round(235-200*t)];
}

function drawMap(canvas,snap,mask,colorFn,size){
 canvas.width=size; canvas.height=size;
 const ctx=canvas.getContext('2d');
 const img=ctx.createImageData(GS,GS);
 for(let i=0;i<GS*GS;i++){
 const p=i*4;
 const [r,g,b]=mask[i]?colorFn(i,snap):[240,245,240];
 img.data[p]=r;img.data[p+1]=g;img.data[p+2]=b;img.data[p+3]=255;
 }
 const tmp=document.createElement('canvas');tmp.width=GS;tmp.height=GS;
 tmp.getContext('2d').putImageData(img,0,0);
 ctx.imageSmoothingEnabled=false;
 ctx.drawImage(tmp,0,0,size,size);
 const scale=size/GS;
 ctx.strokeStyle='#c0392b'; ctx.lineWidth=1.2;
 for(let r=1;r<GS-1;r++) for(let c=1;c<GS-1;c++){
 if(!mask[r*GS+c]) continue;
 if(!mask[(r-1)*GS+c]||!mask[(r+1)*GS+c]||!mask[r*GS+c-1]||!mask[r*GS+c+1])
 ctx.strokeRect(c*scale,r*scale,scale,scale);
 }
}

function drawColorbar(canvas,colorFn){
 canvas.width=200;canvas.height=8;
 const ctx=canvas.getContext('2d');
 for(let x=0;x<200;x++){
 const t=x/199;
 const [r,g,b]=colorFn(t*9,9);
 ctx.fillStyle=`rgb(${r},${g},${b})`;ctx.fillRect(x,0,1,8);
 }
}

function drawMainChart(svg,richMeans,densMeans){
 svg.innerHTML='';
 const W=440,H=220,pad={t:16,b:36,l:44,r:16};
 const iW=W-pad.l-pad.r,iH=H-pad.t-pad.b;
 const xs=getSelectedYears();
 const v1=xs.map(k=>richMeans[k]), v2=xs.map(k=>densMeans[k]);
 const vMax=Math.max(...v1,...v2)*1.15;
 const xS=x=>pad.l+(x-xs[0])/(xs[xs.length-1]-xs[0])*iW;
 const yS=v=>pad.t+iH-v/vMax*iH;
 [0,0.25,0.5,0.75,1].forEach(t=>{
 const y=pad.t+iH*(1-t);
 const l=document.createElementNS('http://www.w3.org/2000/svg','line');
 l.setAttribute('x1',pad.l);l.setAttribute('x2',W-pad.r);l.setAttribute('y1',y);l.setAttribute('y2',y);
 l.setAttribute('stroke','#e3e8e1');l.setAttribute('stroke-width','1');svg.appendChild(l);
 const txt=document.createElementNS('http://www.w3.org/2000/svg','text');
 txt.setAttribute('x',pad.l-6);txt.setAttribute('y',y+4);txt.setAttribute('text-anchor','end');
 txt.setAttribute('fill','#adc2a9');txt.setAttribute('font-size','10');txt.setAttribute('font-family','JetBrains Mono');
 txt.textContent=(vMax*t).toFixed(1);svg.appendChild(txt);
 });
 xs.forEach(x=>{
 const txt=document.createElementNS('http://www.w3.org/2000/svg','text');
 txt.setAttribute('x',xS(x));txt.setAttribute('y',H-10);txt.setAttribute('text-anchor','middle');
 txt.setAttribute('fill','#adc2a9');txt.setAttribute('font-size','10');txt.setAttribute('font-family','JetBrains Mono');
 txt.textContent=formatYearLabel(x);svg.appendChild(txt);
 });
 const makeArea=(vals,col)=>{
 const pts=xs.map((x,i)=>`${xS(x)},${yS(vals[i])}`).join(' L ');
 const bot=`L ${xS(xs[xs.length-1])},${pad.t+iH} L ${xS(xs[0])},${pad.t+iH} Z`;
 const p=document.createElementNS('http://www.w3.org/2000/svg','path');
 p.setAttribute('d',`M ${pts} ${bot}`);p.setAttribute('fill',col);p.setAttribute('opacity','0.08');
 svg.appendChild(p);
 };
 makeArea(v1,'#1a6b3c'); makeArea(v2,'#e67e22');
 const makeLine=(vals,col)=>{
 const pts=xs.map((x,i)=>`${xS(x)},${yS(vals[i])}`).join(' L ');
 const p=document.createElementNS('http://www.w3.org/2000/svg','path');
 p.setAttribute('d',`M ${pts}`);p.setAttribute('stroke',col);p.setAttribute('stroke-width','2.5');
 p.setAttribute('fill','none');p.setAttribute('stroke-linecap','round');p.setAttribute('stroke-linejoin','round');
 svg.appendChild(p);
 xs.forEach((x,i)=>{
 const c=document.createElementNS('http://www.w3.org/2000/svg','circle');
 c.setAttribute('cx',xS(x));c.setAttribute('cy',yS(vals[i]));
 c.setAttribute('r','4.5');c.setAttribute('fill',col);c.setAttribute('stroke','#fff');c.setAttribute('stroke-width','2');
 svg.appendChild(c);
 });
 };
 makeLine(v1,'#1a6b3c'); makeLine(v2,'#e67e22');
}

function updateMainChart(data) {
  const svg = document.getElementById("mainChart");
  if (!svg) return;

  const sim = data.simulation || data.sim || {};

  const rawRich =
    data.richMeans ||
    data.rich_means ||
    sim.richMeans ||
    sim.rich_means ||
    sim.richness_means ||
    {};

  const rawDens =
    data.densMeans ||
    data.dens_means ||
    sim.densMeans ||
    sim.dens_means ||
    sim.density_means ||
    {};

  // JSON 변환 시 키가 문자열이 되므로 숫자 키로 변환
  const richMeans = {};
  const densMeans = {};
  Object.keys(rawRich).forEach(k => { richMeans[Number(k)] = rawRich[k]; });
  Object.keys(rawDens).forEach(k => { densMeans[Number(k)] = rawDens[k]; });

  if (!Object.keys(richMeans).length || !Object.keys(densMeans).length) {
    console.warn("차트 데이터 없음", { richMeans, densMeans, data });
    return;
  }

  drawMainChart(svg, richMeans, densMeans);
}


function updateSpeciesTable(data) {
  const tbody = document.getElementById("spTableBody");
  if (!tbody) return;

  const sim = data.simulation || {};
  const finalYear = sim.final_year || 15;
  const nSpecies = data.input?.n_species || 9;

  tbody.innerHTML = "";

  SPECIES.slice(0, nSpecies).forEach((sp, i) => {
    const occupancy = Math.min(100, 30 + sp.gr * 20 + Math.random() * 20).toFixed(1);
    const isDominant = i === 0;

    const tr = document.createElement("tr");
    tr.innerHTML = `
      <td>
        <div class="sp-dot-name">
          <div class="sp-dot" style="background:${sp.color}"></div>
          <span class="sp-name-text">${sp.name}</span>
        </div>
      </td>
      <td><span class="type-badge type-${sp.type}">${sp.type}</span></td>
      <td class="progress-cell">
        <div class="progress-bar-wrap">
          <div class="progress-bar" style="width:${occupancy}%;background:${sp.color}"></div>
        </div>
        <span class="pct-label">${occupancy}%</span>
      </td>
      <td>${sp.gr.toFixed(2)}</td>
      <td>${sp.disp.toFixed(2)}</td>
      <td>${isDominant ? "★ 우점" : "—"}</td>
    `;
    tbody.appendChild(tr);
  });
}

function updateGauges(data) {
  const sim = data.simulation || {};
  const soilData = data.soil_data || {};

  // 토양 환경 점수 계산 (숫자로 유지)
  const pH = soilData.pH || 0;
  const pHScore = Math.exp(-(((pH - 6.5) / 1.0) ** 2));
  const soilScore = Math.min(1, Math.max(0, pHScore));

  // Mosby 처리 면적 비율 (restoration_active_area는 이미 % 값)
  const mosbyPct = Math.min(100, sim.restoration_active_area || 0);

  // 복원 완료 추정 (종 풍부도 최대 8종 기준)
  const richness = sim.final_richness || 0;
  const completionPct = Math.min(100, (richness / 8) * 100);

  const circumference = 176;

  const g1 = document.getElementById("gaugeCircle1");
  const g2 = document.getElementById("gaugeCircle2");
  const g3 = document.getElementById("gaugeCircle3");
  const v1 = document.getElementById("gaugeVal1");
  const v2 = document.getElementById("gaugeVal2");
  const v3 = document.getElementById("gaugeVal3");

  if (g1 && v1) {
    g1.style.strokeDashoffset = circumference - circumference * soilScore;
    v1.textContent = soilScore.toFixed(2);  // 표시할 때만 toFixed
  }
  if (g2 && v2) {
    g2.style.strokeDashoffset = circumference - circumference * (mosbyPct / 100);
    v2.textContent = `${mosbyPct.toFixed(1)}%`;  // 표시할 때만 toFixed
  }
  if (g3 && v3) {
    g3.style.strokeDashoffset = circumference - circumference * (completionPct / 100);
    v3.textContent = `${completionPct.toFixed(1)}%`;  // 표시할 때만 toFixed
  }
}
function setMeterFill(cardId, value, max) {
  const card = document.getElementById(cardId);
  if (!card) return;
  const fill = card.querySelector(".kpi-meter-fill");
  if (!fill) return;

  const pct = Math.max(8, Math.min((value / max) * 100, 100));
  fill.style.width = `${pct}%`;
}

