function getSiteKey(addr) {
  if (addr.includes('송악산')) return '송악산';
  if (addr.includes('별파랑') || addr.includes('단양')) return '별파랑공원';
  if (addr.includes('석포'))   return '석포제련소';
  return '금오름'; // default
}

function updateMobsyCard(addr, periodMode) {
  const siteKey = getSiteKey(addr);
  const data = MOSBY_IMGS[siteKey] && MOSBY_IMGS[siteKey][periodMode]
    ? MOSBY_IMGS[siteKey][periodMode]
    : (MOSBY_IMGS['금오름'][periodMode] || MOSBY_IMGS['금오름']['long']);
  const bi  = document.getElementById('mobsyBeforeImg');
  const ai  = document.getElementById('mobsyAfterImg');
  const sub = document.getElementById('mobsySub');
  if (bi)  bi.src = data.before;
  if (ai)  ai.src = data.after;
  if (sub) sub.textContent = data.sub;
}


