  const runBtn = document.getElementById("runBtn");
  const addressInput = document.getElementById("addressInput");
  const scenarioSelect = document.getElementById("scenario");
  const nSpeciesSelect = document.getElementById("nSpecies");
  const gridResSelect = document.getElementById("gridRes");
  const clientNameInput = document.getElementById("clientName");
  const clientEmailInput = document.getElementById("clientEmail");

  const loadingOverlay = document.getElementById("loadingOverlay");
  const loadingMsg = document.getElementById("loadingMsg");
  const loadingProgress = document.getElementById("loadingProgress");
  const loadingPct = document.getElementById("loadingPct");

  const emptyState = document.getElementById("emptyState");
  const resultsWrap = document.getElementById("resultsWrap");
  const breadSite = document.getElementById("breadSite");
  const runTimestamp = document.getElementById("runTimestamp");
  const layerList = document.getElementById("layerList");

  function getSelectedPeriod() {
    const activeBtn = document.querySelector("#periodToggle .seg-btn.active");
    return activeBtn ? activeBtn.dataset.period : "long";
  }

  function setLoading(active, message = "시뮬레이션 실행 중...") {
    if (!loadingOverlay) return;

    if (active) {
      loadingOverlay.classList.add("active");
      if (loadingMsg) loadingMsg.textContent = message;
      if (loadingProgress) loadingProgress.style.width = "30%";
      if (loadingPct) loadingPct.textContent = "30%";
      if (runBtn) {
        runBtn.classList.add("loading");
        runBtn.textContent = "실행 중...";
      }
    } else {
      loadingOverlay.classList.remove("active");
      if (loadingProgress) loadingProgress.style.width = "100%";
      if (loadingPct) loadingPct.textContent = "100%";
      if (runBtn) {
        runBtn.classList.remove("loading");
        runBtn.textContent = "▶ 시뮬레이션 실행";
      }
    }
  }

  function updateLayerList(soilData) {
    if (!layerList || !soilData) return;

    const fmt = (value) => {
      if (value === null || value === undefined) return "-";
      if (typeof value === "number") return value.toFixed(2);
      return value;
    };
    const miniPH = document.getElementById("miniPH");
    const miniCa = document.getElementById("miniCa");
    const miniOM = document.getElementById("miniOM");
    const miniCEC = document.getElementById("miniCEC");
    const miniEC = document.getElementById("miniEC");

    if (miniPH) miniPH.textContent = fmt(soilData.pH);
    if (miniCa) miniCa.textContent = fmt(soilData.Ca);
    if (miniOM) miniOM.textContent = fmt(soilData.OM);
    if (miniCEC) miniCEC.textContent = fmt(soilData.CEC);
    if (miniEC) miniEC.textContent = fmt(soilData.EC);

      layerList.innerHTML = `
      <div class="layer-item">
        <div class="layer-left">
          <div class="layer-dot" style="background:#1a6b3c"></div>
          <span class="layer-name">pH</span>
        </div>
        <span class="layer-val">${fmt(soilData.pH)}</span>
      </div>
      <div class="layer-item">
        <div class="layer-left">
          <div class="layer-dot" style="background:#2980b9"></div>
          <span class="layer-name">Ca</span>
        </div>
        <span class="layer-val">${fmt(soilData.Ca)}</span>
      </div>
      <div class="layer-item">
        <div class="layer-left">
          <div class="layer-dot" style="background:#8e44ad"></div>
          <span class="layer-name">OM</span>
        </div>
        <span class="layer-val">${fmt(soilData.OM)}</span>
      </div>
      <div class="layer-item">
        <div class="layer-left">
          <div class="layer-dot" style="background:#e67e22"></div>
          <span class="layer-name">CEC</span>
        </div>
        <span class="layer-val">${fmt(soilData.CEC)}</span>
      </div>
      <div class="layer-item">
        <div class="layer-left">
          <div class="layer-dot" style="background:#c0392b"></div>
          <span class="layer-name">EC</span>
        </div>
        <span class="layer-val">${fmt(soilData.EC)}</span>
      </div>
    `;
  }

  function updateResultSummary(data) {
    if (emptyState) emptyState.style.display = "none";
    if (breadSite) breadSite.textContent = data.input?.address || "-";

    if (runTimestamp) {
      const now = new Date();
      runTimestamp.textContent = now.toLocaleString("ko-KR");
    }
  }

  async function runSimulation() {
    const address = addressInput?.value.trim();
    const scenario = scenarioSelect?.value || "mosby";
    const nSpecies = parseInt(nSpeciesSelect?.value || "9", 10);
    const gridSize = parseInt(gridResSelect?.value || "100", 10);
    const period = getSelectedPeriod();
    const clientName = clientNameInput?.value.trim() || null;
    const clientEmail = clientEmailInput?.value.trim() || null;

    if (!address) {
      alert("주소를 입력해주세요.");
      addressInput?.focus();
      return;
    }

    const payload = {
      address: address,
      scenario: scenario,
      n_species: nSpecies,
      grid_size: gridSize,
      period: period,
      client_name: clientName,
      client_email: clientEmail
    };

    console.log("select raw value =", nSpeciesSelect ? nSpeciesSelect.value : "없음");
    console.log("selected option =", nSpeciesSelect ? nSpeciesSelect.options[nSpeciesSelect.selectedIndex].text : "없음");
    console.log("payload =", payload);

    try {
      setLoading(true, "시뮬레이션 실행 중입니다...");
      console.log("전송 payload:", payload);

      const response = await fetch("/api/simulate", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(payload)
      });

      if (loadingProgress) loadingProgress.style.width = "70%";
      if (loadingPct) loadingPct.textContent = "70%";
      if (loadingMsg) loadingMsg.textContent = "결과를 정리하는 중입니다...";

      const data = await response.json();
      console.log("응답 data:", data);

      if (!response.ok) {
        throw new Error(data.detail || "시뮬레이션 실행 중 오류가 발생했습니다.");
      }
      applySimulationResult(data);

      alert("시뮬레이션이 완료되었습니다.");
    } catch (error) {
      console.error(error);
      alert(`오류: ${error.message}`);
    } finally {
      setLoading(false);
    }
  }

  if (runBtn) {
    runBtn.addEventListener("click", runSimulation);
  }
  initResultView();

  document.querySelectorAll("#periodToggle .seg-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      document.querySelectorAll("#periodToggle .seg-btn").forEach((b) => {
        b.classList.remove("active");
      });
      btn.classList.add("active");
    });
  });

    function renderMapStrip(containerId, items) {
    const container = document.getElementById(containerId);
    if (!container) return;

    container.innerHTML = "";

    items.forEach((item) => {
      const wrap = document.createElement("div");
      wrap.className = "sim-map-wrap";

      const box = document.createElement("div");
      box.className = "sim-map-box";

      const img = document.createElement("img");
      img.src = item.image || "";
      img.alt = `${item.year}년 후`;
      box.appendChild(img);

      const label = document.createElement("div");
      label.className = "sim-map-label";

      const yearTag = document.createElement("span");
      yearTag.className = "sim-year-tag";
      yearTag.textContent = `${item.year}년 후`;

      label.appendChild(yearTag);
      wrap.appendChild(box);
      wrap.appendChild(label);

      container.appendChild(wrap);
    });
  }

  function updateSimulationImages(data) {
    console.log("simulation data =", data);

    const sim = data.simulation || {};
    const mosby = sim.mosby_compare || {};
    const richnessMaps = sim.richness_maps || [];
    const densityMaps = sim.density_maps || [];

    const finalRichness = Number(sim.final_richness ?? 0);
    const finalDensity = Number(sim.final_density ?? 0);
    const restorationActiveArea = Number(
      data.restorationActiveArea ??
      data.restoration_active_area ??
      sim.restorationActiveArea ??
      sim.restoration_active_area ??
      sim.active_area_pct ??
      sim.activeAreaPct ??
      0
    );

    const mobsyBeforeImg = document.getElementById("mobsyBeforeImg");
    const mobsyAfterImg = document.getElementById("mobsyAfterImg");
    const mobsySub = document.getElementById("mobsySub");

    if (mobsyBeforeImg) {
      mobsyBeforeImg.src = mosby.before || "";
    }

    if (mobsyAfterImg) {
      mobsyAfterImg.src = mosby.after || "";
    }

    if (mobsySub) {
      mobsySub.textContent = `이끼 분포 예측 · ${mosby.year || "-"}년차`;
    }

    const kv1 = document.getElementById("kv1");
    const kv2 = document.getElementById("kv2");
    const kv3 = document.getElementById("kv3");

    if (kv1) {
      kv1.textContent = finalRichness.toFixed(2);
    }

    if (kv2) {
      kv2.textContent = finalDensity.toFixed(2);
    }

    if (kv3) {
      kv3.textContent = `${restorationActiveArea.toFixed(2)}%`;
    }

    // KPI 막대 채우기
    setMeterFill("kpiRichnessCard", finalRichness, 9);
    setMeterFill("kpiDensityCard", finalDensity, 15);
    setMeterFill("kpiAreaCard", restorationActiveArea, 100);

    // KPI 카드 상태 뱃지 업데이트
    const richnessState = getRichnessState(finalRichness);
    setStateBadge("kpiRichnessState", richnessState.label, richnessState.cls);
    setCardState("kpiRichnessCard", richnessState.cls);

    const densityState = getDensityState(finalDensity);
    setStateBadge("kpiDensityState", densityState.label, densityState.cls);
    setCardState("kpiDensityCard", densityState.cls);

    const areaState = getAreaState(restorationActiveArea);
    setStateBadge("kpiAreaState", areaState.label, areaState.cls);
    setCardState("kpiAreaCard", areaState.cls);

    renderMapStrip("richnessMapsStrip", richnessMaps);
    renderMapStrip("densityMapsStrip", densityMaps);

    const richnessYearsSub = document.getElementById("richnessYearsSub");
    if (richnessYearsSub && Array.isArray(sim.selected_years)) {
      richnessYearsSub.textContent = sim.selected_years
        .map((y) => `${y}년 후`)
        .join(" · ");
    }
  }

  function applySimulationResult(data) {
    updateLayerList(data.soil_data);
    updateResultSummary(data);
    updateSimulationImages(data);

    if (typeof updateMainChart === "function") updateMainChart(data);
    if (typeof updateSpeciesTable === "function") updateSpeciesTable(data);
    if (typeof updateSummary === "function") updateSummary(data);

    const emptyState = document.getElementById("emptyState");
    const resultsWrap = document.getElementById("resultsWrap");

    if (emptyState) emptyState.style.display = "none";
    if (resultsWrap) resultsWrap.classList.add("visible");
  }
  function initResultView() {
    const emptyState = document.getElementById("emptyState");
    const resultsWrap = document.getElementById("resultsWrap");

    if (emptyState) emptyState.style.display = "flex";
    if (resultsWrap) resultsWrap.classList.remove("visible");
  }
  document.addEventListener("DOMContentLoaded", function () {
    const addressInput = document.getElementById("addressInput");

    document.querySelectorAll(".preset-btn").forEach((btn) => {
      btn.addEventListener("click", () => {
        if (addressInput) {
          addressInput.value = btn.dataset.address || "";
        }
      });
    });
  });

// 제출 버튼 이벤트 추가
const submitBtn = document.getElementById("submitClientBtn");

if (submitBtn) {
  submitBtn.addEventListener("click", function () {
    const nameInput = document.getElementById("clientName");
    const emailInput = document.getElementById("clientEmail");
    const msg = document.getElementById("clientSubmitMsg");

    const name = nameInput ? nameInput.value.trim() : "";
    const email = emailInput ? emailInput.value.trim() : "";

    if (!name || !email) {
      alert("이름과 이메일을 입력하세요");
      return;
    }

    if (msg) msg.style.display = "block";

    submitBtn.classList.add("done");
    submitBtn.innerText = "등록됨";
    submitBtn.disabled = true;

    if (nameInput) nameInput.disabled = true;
    if (emailInput) emailInput.disabled = true;
  });
}

  function submitInquiry() {
  const contactInput = document.getElementById("inquiryContact");
  const siteInput = document.getElementById("inquirySite");
  const msg = document.getElementById("inquirySubmitMsg");
  const btn = document.getElementById("submitInquiryBtn");

  const contact = contactInput ? contactInput.value.trim() : "";
  const site = siteInput ? siteInput.value.trim() : "";

  if (!contact) {
    alert("연락받을 주소를 입력해주세요.");
    return;
  }

  if (!site) {
    alert("정밀 분석 대상지 주소를 입력해주세요.");
    return;
  }

  if (msg) msg.style.display = "block";

  if (btn) {
    btn.classList.add("done");
    btn.textContent = "접수 완료";
    btn.disabled = true;
  }

  if (contactInput) contactInput.disabled = true;
  if (siteInput) siteInput.disabled = true;

  console.log("정밀 분석 문의 접수", { contact, site });
}

const submitInquiryBtn = document.getElementById("submitInquiryBtn");
if (submitInquiryBtn) {
  submitInquiryBtn.addEventListener("click", submitInquiry);
}